/** Datos de lecciones para cursos 2–12 (importado por build-new-courses.mjs) */
export function mk(title, concept, practice, exampleContent, tip, question, options, correct) {
  return {
    title,
    concept,
    practice,
    exampleTitle: `Ejemplo: ${title}`,
    exampleContent,
    tip,
    question,
    options,
    correct,
  };
}

export function mod(title, description, rows) {
  return { title, description, lessons: rows.map((r) => mk(...r)) };
}

